import type * as SarvamAI from "../index.js";
/**
 * Response for download-files endpoint.
 */
export interface DocDigitizationDownloadFilesResponse {
    /** Job identifier (UUID) */
    job_id: string;
    /** Current job state */
    job_state: SarvamAI.DocDigitizationJobState;
    /** Storage backend type */
    storage_container_type: SarvamAI.StorageContainerType;
    /** Map of filename to presigned download URL details */
    download_urls: Record<string, SarvamAI.FileSignedUrlDetails>;
    error_code?: string | undefined;
    error_message?: string | undefined;
}
